mapper.select:
select case when count(*) > 0 then true else false end
from user_task_event_log
where user_id = #{userId, jdbcType=BINARY}
  and task_code = #{taskCode}
  and period_key = #{periodKey}
  and source_event_id = #{sourceEventId}

